using SkiaSharpChartEngine; using SkiaSharpChartEngine.Models; class Program { static void Main(string[] args) { var engine = ChartEngine.Create(); var chart = new Chart(ChartType.BarChart) { Configuration = new ChartConfiguration { Title = "Docker Deployment Chart", Width = 800, Height = 600 } }; var series = new ChartSeries("Products", "#4ECDC4"); series.AddDataPoint(1, 45000); series.AddDataPoint(2, 52000); series.AddDataPoint(3, 38000); chart.AddSeries(series); var result = engine.RenderChart(chart); System.IO.File.WriteAllBytes("docker-chart.png", result.Data as byte[]); } }